// ===== EXTRACT AD COPY FROM ALL PLATFORMS =====

function extractTitle(ad) {
  if (ad.headline && typeof ad.headline === 'object') {
    const t = ad.headline.title || ad.headline.description;
    if (t && !t.includes('{{')) return t;
  }
  if (ad.commentary && ad.commentary.text && !ad.commentary.text.includes('{{')) {
    return ad.commentary.text.substring(0, 120);
  }
  if (ad.snapshot) {
    if (Array.isArray(ad.snapshot.cards) && ad.snapshot.cards.length > 0) {
      for (const card of ad.snapshot.cards) {
        if (card.title && !card.title.includes('{{')) return card.title;
        if (card.body && typeof card.body === 'string' && !card.body.includes('{{')) return card.body.substring(0, 120);
      }
    }
    if (ad.snapshot.title && !ad.snapshot.title.includes('{{')) return ad.snapshot.title;
    if (ad.snapshot.body) {
      const bodyText = typeof ad.snapshot.body === 'object' ? ad.snapshot.body.text : ad.snapshot.body;
      if (bodyText && !bodyText.includes('{{')) return bodyText.substring(0, 120);
    }
  }
  if (typeof ad.title === 'string' && !ad.title.includes('{{')) return ad.title;
  if (typeof ad.ad_title === 'string' && ad.ad_title !== 'N/A') return ad.ad_title;
  return null;
}

function extractBody(ad) {
  // Try to get longer body copy beyond the title
  if (ad.snapshot) {
    if (ad.snapshot.body) {
      const b = typeof ad.snapshot.body === 'object' ? ad.snapshot.body.text : ad.snapshot.body;
      if (b && b.length > 0) return b.substring(0, 300);
    }
    if (Array.isArray(ad.snapshot.cards) && ad.snapshot.cards.length > 0) {
      const bodies = ad.snapshot.cards
        .map(c => c.body || c.description || '')
        .filter(Boolean)
        .join(' | ');
      if (bodies) return bodies.substring(0, 300);
    }
  }
  if (ad.commentary && ad.commentary.text) return ad.commentary.text.substring(0, 300);
  if (ad.description) return String(ad.description).substring(0, 300);
  return '';
}

function getMonday(d) {
  const date = new Date(d);
  const day = date.getDay();
  const diff = date.getDate() - day + (day === 0 ? -6 : 1);
  date.setDate(diff);
  return date.toISOString().split('T')[0];
}

const items = $input.all();
const adRows = [];
const weekOf = getMonday(new Date());

// Get domain and competitor_name from Loop node
let domain = '';
let competitorName = '';
try {
  const loopItem = $('Loop Over Competitors').item.json;
  domain = loopItem.domain || loopItem.Domain || '';
  competitorName = loopItem.competitor_name || loopItem.Competitor_Name || loopItem.name || loopItem.Name || '';
} catch(e) {
  for (const item of items) {
    if (item.json.domain) { domain = item.json.domain; }
    if (item.json.competitor_name) { competitorName = item.json.competitor_name; }
  }
}

const snapshotId = `${domain}_${weekOf}`;

for (const item of items) {
  const data = item.json;

  // Facebook/Meta
  if (data.results && Array.isArray(data.results)) {
    const fbAds = data.results.flat();
    for (const ad of fbAds) {
      const title = extractTitle(ad);
      if (!title) continue;
      adRows.push({
        snapshot_id:      snapshotId,
        domain:           domain,
        competitor_name:  competitorName,
        week_of:          weekOf,
        platform:         'Meta',
        ad_title:         title,
        ad_body:          extractBody(ad),
        captured_at:      new Date().toISOString()
      });
    }
  }

  // LinkedIn / Google
  if (data.ads && Array.isArray(data.ads)) {
    for (const ad of data.ads) {
      let platform = 'Google';
      if (ad.view_details_link && ad.view_details_link.includes('linkedin.com')) {
        platform = 'LinkedIn';
      } else if (ad.headline || ad.commentary) {
        platform = 'LinkedIn';
      }
      const title = extractTitle(ad);
      if (!title) continue;
      adRows.push({
        snapshot_id:      snapshotId,
        domain:           domain,
        competitor_name:  competitorName,
        week_of:          weekOf,
        platform:         platform,
        ad_title:         title,
        ad_body:          extractBody(ad),
        captured_at:      new Date().toISOString()
      });
    }
  }
}

// Deduplicate by ad_title + platform
const seen = new Set();
const deduped = adRows.filter(row => {
  const key = `${row.platform}::${row.ad_title}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

if (deduped.length === 0) {
  // No ads found — return a sentinel so downstream nodes can handle gracefully
  return [{
    json: {
      snapshot_id:      snapshotId,
      domain:           domain,
      competitor_name:  competitorName,
      week_of:          weekOf,
      platform:         'N/A',
      ad_title:         'NO_ADS_FOUND',
      ad_body:          '',
      captured_at:      new Date().toISOString(),
      _no_ads:          true
    }
  }];
}

return deduped.map(r => ({ json: r }));

// ===== AGGREGATE THIS WEEK'S COPY INTO A SINGLE CONTEXT OBJECT =====
// Groups all ad rows for this competitor into one item for comparison

const items = $input.all();
if (!items || items.length === 0) {
  return [{ json: { error: 'No input items', _skip: true } }];
}

const first = items[0].json;

// If no ads found sentinel
if (first._no_ads) {
  return [{
    json: {
      domain:          first.domain,
      competitor_name: first.competitor_name,
      week_of:         first.week_of,
      snapshot_id:     first.snapshot_id,
      this_week_rows:  [],
      this_week_text:  'No ads found this week.',
      _no_ads:         true
    }
  }];
}

const domain          = first.domain;
const competitorName  = first.competitor_name;
const weekOf          = first.week_of;
const snapshotId      = first.snapshot_id;

// Build a readable text block of all this week's ads for the LLM
const allRows = items.map(i => i.json);
const lines = allRows.map(r => {
  const body = r.ad_body ? ` | Body: ${r.ad_body}` : '';
  return `[${r.platform}] ${r.ad_title}${body}`;
});

const thisWeekText = lines.join('\n');

return [{
  json: {
    domain:          domain,
    competitor_name: competitorName,
    week_of:         weekOf,
    snapshot_id:     snapshotId,
    this_week_rows:  allRows,
    this_week_text:  thisWeekText,
    _no_ads:         false
  }
}];

// ===== FIND LAST WEEK'S SNAPSHOT & BUILD COMPARISON CONTEXT =====

const allItems = $input.all();

// Get the aggregated this-week data from upstream
let thisWeekData = {};
try {
  thisWeekData = $('Aggregate This Week\'s Copy').first().json;
} catch(e) {
  return [{ json: { error: 'Could not read this week data', _skip: true } }];
}

const domain      = thisWeekData.domain;
const weekOf      = thisWeekData.week_of;
const thisWeekText = thisWeekData.this_week_text || 'No ads found this week.';

// Calculate last Monday's date
function getPreviousMonday(weekOfStr) {
  const d = new Date(weekOfStr);
  d.setDate(d.getDate() - 7);
  return d.toISOString().split('T')[0];
}
const previousWeek = getPreviousMonday(weekOf);

// Filter sheet rows to only last week's entries for this domain
const lastWeekRows = allItems
  .map(i => i.json)
  .filter(r => r.domain === domain && r.week_of === previousWeek);

let lastWeekText = '';
if (lastWeekRows.length === 0) {
  lastWeekText = 'No previous week data available (first run or no ads last week).';
} else {
  const lines = lastWeekRows.map(r => {
    const body = r.ad_body ? ` | Body: ${r.ad_body}` : '';
    return `[${r.platform}] ${r.ad_title}${body}`;
  });
  lastWeekText = lines.join('\n');
}

// Build unique title sets for new/dropped detection
const thisWeekTitles = new Set(
  (thisWeekData.this_week_rows || []).map(r => r.ad_title)
);
const lastWeekTitles = new Set(
  lastWeekRows.map(r => r.ad_title)
);

const newTitles     = [...thisWeekTitles].filter(t => !lastWeekTitles.has(t));
const droppedTitles = [...lastWeekTitles].filter(t => !thisWeekTitles.has(t));

return [{
  json: {
    domain:               domain,
    competitor_name:      thisWeekData.competitor_name,
    week_of:              weekOf,
    previous_week:        previousWeek,
    snapshot_id:          thisWeekData.snapshot_id,
    this_week_text:       thisWeekText,
    last_week_text:       lastWeekText,
    new_titles:           newTitles,
    dropped_titles:       droppedTitles,
    this_week_rows:       thisWeekData.this_week_rows || [],
    is_first_run:         lastWeekRows.length === 0,
    _no_ads:              thisWeekData._no_ads || false
  }
}];

