// ===== PARSE AI OUTPUT — HANDLES JSON AND PLAIN TEXT =====

const items = $input.all();
const data  = items[0].json;

let aiResult = {
  angle_shift:        'N/A',
  new_audiences:      'N/A',
  new_value_props:    'N/A',
  urgency_signal:     'N/A',
  urgency_reason:     'N/A',
  delta_summary:      'N/A',
  new_ad_titles:      'N/A',
  dropped_ad_titles:  'N/A'
};

let rawText = '';
if (typeof data.output === 'string')      rawText = data.output;
else if (typeof data.text === 'string')   rawText = data.text;
else if (typeof data === 'string')        rawText = data;
else                                      rawText = JSON.stringify(data);

// Attempt 1: parse as JSON
let parsedFromJson = false;
try {
  const cleaned = rawText
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/gi, '')
    .trim();
  const start = cleaned.indexOf('{');
  const end   = cleaned.lastIndexOf('}');
  if (start !== -1 && end !== -1) {
    const parsed = JSON.parse(cleaned.substring(start, end + 1));
    // Validate it has at least one real field
    if (parsed.delta_summary || parsed.angle_shift) {
      aiResult.angle_shift       = parsed.angle_shift       || 'N/A';
      aiResult.new_audiences     = parsed.new_audiences     || 'N/A';
      aiResult.new_value_props   = parsed.new_value_props   || 'N/A';
      aiResult.urgency_signal    = parsed.urgency_signal    || 'N/A';
      aiResult.urgency_reason    = parsed.urgency_reason    || 'N/A';
      aiResult.delta_summary     = parsed.delta_summary     || 'N/A';
      aiResult.new_ad_titles     = parsed.new_ad_titles     || 'N/A';
      aiResult.dropped_ad_titles = parsed.dropped_ad_titles || 'N/A';
      parsedFromJson = true;
    }
  }
} catch (e) {}

// Attempt 2: regex field extraction
if (!parsedFromJson) {
  function extract(text, field) {
    const re = new RegExp('"' + field + '"\\s*:\\s*"([^"]+)"');
    const m  = text.match(re);
    return m ? m[1] : null;
  }
  aiResult.angle_shift       = extract(rawText, 'angle_shift')       || aiResult.angle_shift;
  aiResult.new_audiences     = extract(rawText, 'new_audiences')     || aiResult.new_audiences;
  aiResult.new_value_props   = extract(rawText, 'new_value_props')   || aiResult.new_value_props;
  aiResult.urgency_signal    = extract(rawText, 'urgency_signal')    || aiResult.urgency_signal;
  aiResult.urgency_reason    = extract(rawText, 'urgency_reason')    || aiResult.urgency_reason;
  aiResult.delta_summary     = extract(rawText, 'delta_summary')     || aiResult.delta_summary;
  aiResult.new_ad_titles     = extract(rawText, 'new_ad_titles')     || aiResult.new_ad_titles;
  aiResult.dropped_ad_titles = extract(rawText, 'dropped_ad_titles') || aiResult.dropped_ad_titles;

  // Attempt 3: plain-text fallback — use the whole output as delta_summary
  if (aiResult.delta_summary === 'N/A' && rawText.length > 10) {
    aiResult.delta_summary = rawText.trim().substring(0, 400);

    // Try to detect urgency from keywords
    const lower = rawText.toLowerCase();
    if (lower.includes('significant') || lower.includes('pivot') || lower.includes('major') || lower.includes('new product') || lower.includes('launch')) {
      aiResult.urgency_signal = 'High';
    } else if (lower.includes('minor') || lower.includes('slight') || lower.includes('small')) {
      aiResult.urgency_signal = 'Low';
    } else {
      aiResult.urgency_signal = 'Medium';
    }
  }
}

// Get comparison context from Build Comparison Context node
let compData = {};
try {
  compData = $('Build Comparison Context').first().json;
} catch(e) {}

const domain          = compData.domain          || '';
const competitorName  = compData.competitor_name || '';
const weekOf          = compData.week_of         || '';
const previousWeek    = compData.previous_week   || '';
const newTitles       = (compData.new_titles     || []).join('; ') || 'None';
const droppedTitles   = (compData.dropped_titles || []).join('; ') || 'None';

return [{
  json: {
    domain:               domain,
    competitor_name:      competitorName,
    week_of:              weekOf,
    previous_week:        previousWeek,
    new_ad_titles:        aiResult.new_ad_titles !== 'N/A' ? aiResult.new_ad_titles : newTitles,
    dropped_ad_titles:    aiResult.dropped_ad_titles !== 'N/A' ? aiResult.dropped_ad_titles : droppedTitles,
    angle_shift:          aiResult.angle_shift,
    new_audiences:        aiResult.new_audiences,
    new_value_props:      aiResult.new_value_props,
    urgency_signal:       aiResult.urgency_signal,
    urgency_reason:       aiResult.urgency_reason,
    delta_summary:        aiResult.delta_summary,
    analyzed_at:          new Date().toISOString()
  }
}];

// ===== PREPARE SNAPSHOT ROWS FOR WRITING =====
// Runs AFTER delta is saved — this becomes next week's 'last week'

let thisWeekRows = [];
try {
  const compData = $('Build Comparison Context').first().json;
  thisWeekRows   = compData.this_week_rows || [];
} catch(e) {
  return [{ json: { _skip: true, error: 'Could not read this_week_rows' } }];
}

if (thisWeekRows.length === 0) {
  return [{ json: { _skip: true } }];
}

return thisWeekRows.map(r => ({ json: r }));

// ===== FORMAT SLACK ALERT =====

const data = $input.first().json;

// Read delta result — check both Parse Delta Result and fallback
let deltaData = data;
try {
  deltaData = $('Parse Delta Result').first().json;
} catch(e) {}

const urgencyEmoji = {
  'High':   '🔴',
  'Medium': '🟡',
  'Low':    '🟢'
};

const emoji = urgencyEmoji[deltaData.urgency_signal] || '⚪';

const message = [
  `${emoji} *Competitor Messaging Alert* — ${deltaData.urgency_signal} Urgency`,
  `*Competitor:* ${deltaData.competitor_name} (${deltaData.domain})`,
  `*Week:* ${deltaData.week_of} vs ${deltaData.previous_week}`,
  ``,
  `*What changed:* ${deltaData.delta_summary}`,
  ``,
  `*Angle shift:* ${deltaData.angle_shift}`,
  `*New audiences:* ${deltaData.new_audiences}`,
  `*New value props:* ${deltaData.new_value_props}`,
  ``,
  `*New ads:* ${deltaData.new_ad_titles}`,
  `*Dropped ads:* ${deltaData.dropped_ad_titles}`
].join('\n');

return [{
  json: {
    slack_message: message,
    competitor_name: deltaData.competitor_name,
    urgency_signal:  deltaData.urgency_signal
  }
}];

// ===== BUILD NO-ADS DELTA ROW =====
// When a competitor had no ads this week, log it as a Low urgency delta

const data = $input.first().json;

let compData = {};
try {
  compData = $('Build Comparison Context').first().json;
} catch(e) {}

const domain         = compData.domain          || data.domain         || '';
const competitorName = compData.competitor_name || data.competitor_name || '';
const weekOf         = compData.week_of         || data.week_of        || '';
const previousWeek   = compData.previous_week   || '';

return [{
  json: {
    domain:               domain,
    competitor_name:      competitorName,
    week_of:              weekOf,
    previous_week:        previousWeek,
    new_ad_titles:        'None',
    dropped_ad_titles:    'All ads — no active ads found this week',
    angle_shift:          'No active ads detected this week',
    new_audiences:        'N/A',
    new_value_props:      'N/A',
    urgency_signal:       'Medium',
    urgency_reason:       'Competitor has gone dark — potential budget pause or campaign reset',
    delta_summary:        `${competitorName} had no detectable active ads this week across Meta, Google, and LinkedIn. This could indicate a budget pause, campaign reset, or preparation for a new launch.`,
    analyzed_at:          new Date().toISOString()
  }
}];
